    my $computed_b64 = en_base64($check_hash);

    return _constant_time_compare($computed_b64, $expected_hash_b64);
}

sub _de_base64 {
    my ($text) = @_;
    # Crypt::Eksblowfish::Bcrypt base64: ./A-Za-z0-9
    my @chars = ('.', '/', 'A'..'Z', 'a'..'z', '0'..'9');
